create table if not exists study_tracker_ideas (
  id bigserial primary key,
  seed_key text unique null,
  presented_at date null,
  presenter text not null,
  company_name text not null,
  ticker text not null,
  sector text null,
  pitch_price numeric(20,6) null,
  target_price numeric(20,6) null,
  pitch_upside_pct numeric(12,8) null,
  currency text null,
  current_price numeric(20,6) null,
  current_upside_pct numeric(12,8) null,
  current_return_pct numeric(12,8) null,
  thesis text null,
  trigger text null,
  risk text null,
  style text null,
  status text null,
  entry_date date null,
  exit_date date null,
  close_return_pct numeric(12,8) null,
  note text null,
  tracking_return_pct numeric(12,8) null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  constraint chk_study_tracker_currency check (currency is null or currency in ('KRW', 'USD'))
);

create index if not exists idx_study_tracker_presented_at on study_tracker_ideas(presented_at desc, id desc);
create index if not exists idx_study_tracker_status on study_tracker_ideas(status);
create index if not exists idx_study_tracker_sector on study_tracker_ideas(sector);

drop trigger if exists trg_study_tracker_touch on study_tracker_ideas;
create trigger trg_study_tracker_touch
before update on study_tracker_ideas
for each row
execute function touch_updated_at();

